<?php
 declare(strict_types=1); namespace tapmeppe\composer\database\seeders; use Illuminate\Support\Facades\DB; class ContactsAdministrator extends \tapmeppe\composer\helpers\Seeder { public function runInner(array $parameters): bool { $role = DB::table('roles')->where('name', 'Administrator')->first()->id; $users = DB::table('users'); if ($users->where('role_id', $role)->count()) return false; $users->updateOrInsert( ['id' => $users->count() + 1], [ 'password' => password_hash($parameters['password'], PASSWORD_BCRYPT, ['cost' => 10]), 'role_id' => $role, 'status' => 1, ] + $parameters ); return true; } } 